//! Academy internal store for Hydra.\n//!\n//! Each Hydra organism owns a local append-only academy journal and a\n//! searchable view over shared Academia entries. Every append is logged\n//! with full metadata; every read is deterministic.\n\nuse std::collections::BTreeMap;\nuse std::fs::{self, OpenOptions};\nuse std::io::Write;\nuse std::path::PathBuf;\n\nuse crate::academia::Academia;\n\n#[derive(Debug, Clone)]\npub struct AcademyEntry {\n    pub ts_ns: u64,\n    pub cycle: u64,\n    pub actor: [u8; 32],\n    pub title: String,\n    pub source: String,\n    pub tags: Vec<String>,\n}\n\n#[derive(Debug, Default)]\npub struct AcademyStore {\n    pub entries: Vec<AcademyEntry>,\n    pub search_index: BTreeMap<String, Vec<usize>>,\n}\n\nimpl AcademyStore {\n    /// Append a new record to the journal.\n    pub fn append(\n        &mut self,\n        cycle: u64,\n        actor: [u8; 32],\n        title: impl Into<String>,\n        source: impl Into<String>,\n        tags: Vec<String>,\n    ) -> usize {\n        let entry = AcademyEntry {\n            ts_ns: 0,\n            cycle,\n            actor,\n            title: title.into(),\n            source: source.into(),\n            tags,\n        };\n        let idx = self.entries.len();\n        self.entries.push(entry);\n        self.reindex(idx);\n        idx\n    }\n\n    fn reindex(&mut self, idx: usize) {\n        let entry = &self.entries[idx];\n        let norm = entry.title.to_lowercase();\n        self.search_index\n            .entry(norm)\n            .or_default()\n            .push(idx);\n    }\n\n    /// Search local journal by title substring. Returns matched indices.\n    pub fn search(&self, query: &str) -> Vec<usize> {\n        let q = query.to_lowercase();\n        self.search_index\n            .iter()\n            .filter_map(|(key, idxs)| {\n                if key.contains(&q) {\n                    Some(idxs.clone())\n                } else {\n                    None\n                }\n            })\n            .flatten()\n            .collect()\n    }\n\n    /// Get an entry by index.\n    pub fn get(&self, idx: usize) -> Option<&AcademyEntry> {\n        self.entries.get(idx)\n    }\n\n    /// Total entries.\n    pub fn len(&self) -> usize {\n        self.entries.len()\n    }\n}\n\n/// Persist academy entries to a JSONL file.\npub fn journal_write(path: PathBuf, entries: &[AcademyEntry]) {\n    if let Ok(mut f) = OpenOptions::new().create(true).append(true).open(path) {\n        for entry in entries {\n            let _ = writeln!(\n                f,\n                \"{{\\\"ts_ns\\\":{},\\\"cycle\\\":{},\\\"actor\\\":\\\"{}\\\",\\\"title\\\":\\\"{}\\\",\\\"source\\\":\\\"{}\\\",\\\"tags\\\":{:?}}}\",\n                entry.ts_ns,\n                entry.cycle,\n                hex::encode(entry.actor),\n                json_escape(&entry.title),\n                json_escape(&entry.source),\n                entry.tags\n            );\n        }\n    }\n}\n\n/// Helper to escape JSON strings manually.\nfn json_escape(s: &str) -> String {\n    s.replace('\\\\', \"\\\\\")\\\n        .replace('\\n', \"\\\\n\")\\\n        .replace('\\r', \"\\\\r\")\\\n        .replace('\\t', \"\\\\t\")\n}\n"
